      musicParams: {"key": "A", "chordNotes": [110.0, 138.59, 164.81, 220.0], "padType": "resonant", "padGain": 0.0406, "padFilter": 852, "padLfo": 0.0824, "noiseType": "pink", "noiseGain": 0.0122, "droneFreq": 55.0, "droneGain": 0.0368, "melodyNotes": [220.0, 277.18, 329.62, 293.66], "melodyInterval": 3953, "melodyGain": 0.0177, "bassNotes": [55.0, 82.41, 69.3], "bassInterval": 6434, "counterNotes": [346.48, 412.02, 275.0], "counterInterval": 4778, "events": [{"type": "windGust", "interval": 13329}, {"type": "leaves", "interval": 8621}, {"type": "birdChirp", "interval": 16162}, {"type": "owl", "interval": 24420}], "soundscapePreset": "garden", "musicLoop": "gentleGuitar"},
